import csv; rows=[]; f=open('/home/mettaclaw/artifacts/probe_mutation_log.csv'); r=csv.DictReader(f); [rows.append((int(row['probe_count']),int(row['delta_atoms']))) for row in r]; f.close(); n=len(rows); px=[x for x,y in rows]; dy=[y for x,y in rows]; mx=sum(px)/n; my=sum(dy)/n; num=sum((x-mx)*(y-my) for x,y in rows); den=(sum((x-mx)**2 for x in px)**0.5)*(sum((y-my)**2 for y in dy)**0.5); print(f'N={n} mean_probe={mx:.1f} mean_delta={my:.2f} Pearson_r={num/den:.4f}' if den>0 else 'zero variance')